const fastify = require('fastify')({ logger: true });
const crypto = require('crypto');
const rawBody = require('fastify-raw-body');

const PORT = process.env.PORT || 3000;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

fastify.register(rawBody, {
  field: 'rawBody',
  global: true,
  encoding: false, // get Buffer
  runFirst: true,
});

fastify.post('/webhook', async (request, reply) => {
  const signature = request.headers['x-prembly-signature'];

  if (!signature) {
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  if (!PREMBLY_API_KEY) {
    request.log.error('PREMBLY_API_KEY environment variable is not set');
    return reply.status(500).send({ error: 'Configuration error' });
  }

  // Compute HMAC-SHA256 signature
  const hmac = crypto.createHmac('sha256', PREMBLY_API_KEY);
  hmac.update(request.rawBody);
  const computedSignature = hmac.digest('base64');

  // Compare signatures
  if (computedSignature !== signature) {
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  // Valid signature, process the webhook
  return reply.status(200).send({ status: 'received' });
});

const start = async () => {
  try {
    await fastify.listen({ port: PORT, host: '0.0.0.0' });
    console.log(`Server listening on port ${PORT}`);
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};

start();

